// Normalize both trigger shapes to: { project_id, force, via_webhook }
const raw = $input.first().json;
// Webhook payload lives in `body`; Execute Workflow trigger passes direct JSON
const payload = raw.body || raw;

const projectId = payload.project_id;
if (!projectId) {
  throw new Error('WF_RPM_CLASSIFY requires { project_id } in payload');
}

const force = payload.force === true;

return [{
  json: {
    project_id: projectId,
    force,
    via_webhook: !!raw.body,
    triggered_at: new Date().toISOString()
  }
}];

// CF03 WF_RPM_CLASSIFY — classify project niche into 1 of 12 categories,
// look up rpm_benchmarks, compute revenue_potential_score, PATCH project,
// log to production_logs, return structured response.
// Global fetch + $env per MEMORY.md (n8n 2.8.4 task runner compat).

const input = $input.first().json;
const projectId = input.project_id;
const force = input.force === true;
const viaWebhook = input.via_webhook === true;
const runStart = Date.now();

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};
const anthropicKey = $env.ANTHROPIC_API_KEY;

const VALID_CATEGORIES = [
  'finance', 'credit_cards', 'insurance', 'health_wellness',
  'software_saas', 'education', 'business', 'gaming',
  'entertainment', 'travel', 'cooking', 'tech_reviews'
];

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

// Compute revenue_potential_score (0-100) from rpm_mid using log scale.
// mid=1 -> 32, mid=10 -> 62, mid=28 -> 78, mid=45 -> 86.
function computeRevenueScore(rpmMid) {
  const mid = Math.max(0, Number(rpmMid) || 0);
  const raw = 40 * Math.log10(mid + 1) + 20;
  return Math.max(0, Math.min(100, Math.round(raw)));
}

async function logProduction(action, status, durationMs, costUsd, retryCount) {
  try {
    await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: projectId,
        topic_id: null,
        stage: 'rpm_classify',
        scene_number: null,
        action,
        status,
        duration_ms: durationMs,
        cost_usd: costUsd,
        retry_count: retryCount
      })
    });
  } catch (_) { /* best-effort logging */ }
}

async function lookupBenchmark(category) {
  const url = `${supabaseUrl}/rest/v1/rpm_benchmarks?category=eq.${encodeURIComponent(category)}&select=rpm_low,rpm_mid,rpm_high,display_name`;
  const res = await fetch(url, { method: 'GET', headers: sbHeaders });
  if (!res.ok) return null;
  const arr = await res.json();
  return Array.isArray(arr) && arr.length ? arr[0] : null;
}

async function patchProject(patch) {
  const res = await fetch(`${supabaseUrl}/rest/v1/projects?id=eq.${projectId}`, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify(patch)
  });
  if (!res.ok) {
    const body = await res.text();
    throw new Error(`PATCH project failed: HTTP ${res.status}: ${body.slice(0, 200)}`);
  }
}

// 1. Fetch project
const projUrl = `${supabaseUrl}/rest/v1/projects?id=eq.${projectId}&select=id,niche,niche_description,niche_expertise_profile,niche_rpm_category,estimated_rpm_low,estimated_rpm_mid,estimated_rpm_high,revenue_potential_score,rpm_classified_at`;
const projRes = await fetch(projUrl, { method: 'GET', headers: sbHeaders });
if (!projRes.ok) {
  throw new Error(`Fetch project failed: HTTP ${projRes.status}: ${await projRes.text()}`);
}
const projArr = await projRes.json();
const project = projArr[0];
if (!project) {
  return [{
    json: {
      success: false,
      project_id: projectId,
      error: 'Project not found',
      http_status: 404,
      via_webhook: viaWebhook
    }
  }];
}

// 2. Idempotency: skip if already classified and not forced
if (project.niche_rpm_category && !force) {
  await logProduction('idempotent_skip', 'skipped', Date.now() - runStart, 0, 0);
  return [{
    json: {
      success: true,
      project_id: projectId,
      category: project.niche_rpm_category,
      rpm_low: project.estimated_rpm_low,
      rpm_mid: project.estimated_rpm_mid,
      rpm_high: project.estimated_rpm_high,
      revenue_potential_score: project.revenue_potential_score,
      classification_confidence: null,
      reasoning: 'Already classified (pass force=true to reclassify)',
      classified_by_fallback: false,
      skipped: true,
      via_webhook: viaWebhook
    }
  }];
}

// 3. Build Claude user prompt
const niche = project.niche || '';
const nicheDesc = project.niche_description || '';
const nicheExpertise = project.niche_expertise_profile || '';

const userPrompt = `Classify this YouTube channel niche into exactly one of these 12 categories.

Niche: ${niche}
Description: ${nicheDesc}
Expertise Profile: ${nicheExpertise}

Categories (pick the best single fit):
- finance           — general personal finance, investing, markets
- credit_cards      — credit card rewards, travel cards, card comparisons
- insurance         — life, auto, health, property insurance
- health_wellness   — fitness, nutrition, supplements, mental health
- software_saas     — B2B tools, dev tools, productivity software
- education         — K-12, higher ed, online courses, study skills
- business          — entrepreneurship, small business, career, sales
- gaming            — video games, esports, gaming hardware
- entertainment     — pop culture, reactions, comedy, celebrity
- travel            — destinations, travel tips, hotel/flight reviews
- cooking           — recipes, technique, kitchen gear, food travel
- tech_reviews      — consumer electronics, gadget reviews, phones

Return ONLY this JSON (no other text, no code fences):
{"category": "<one of the 12>", "confidence": <float 0-1>, "reasoning": "<1 sentence>"}`;

// 4. Call Claude with inline exponential backoff (1s -> 2s -> 4s -> 8s, max 4)
const MAX_RETRIES = 4;
let retryCount = 0;
let claudeOk = false;
let claudeText = '';
let claudeError = null;
const claudeStart = Date.now();

for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
  try {
    const res = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': anthropicKey,
        'anthropic-version': '2023-06-01',
        'content-type': 'application/json'
      },
      body: JSON.stringify({
        model: 'claude-opus-4-6',
        max_tokens: 200,
        messages: [{ role: 'user', content: userPrompt }]
      })
    });
    if (res.ok) {
      const body = await res.json();
      claudeText = body.content?.[0]?.text || '';
      claudeOk = true;
      break;
    }
    const errBody = await res.text();
    claudeError = `HTTP ${res.status}: ${errBody.slice(0, 200)}`;
    // Non-retryable 4xx (except 429)
    if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
  } catch (e) {
    claudeError = e.message;
  }
  if (attempt < MAX_RETRIES) {
    retryCount += 1;
    const delay = Math.min(1000 * Math.pow(2, attempt - 1), 30000);
    await sleep(delay);
  }
}
const claudeDuration = Date.now() - claudeStart;

// 5. Parse Claude response
let parsed = null;
if (claudeOk && claudeText) {
  const clean = claudeText.replace(/```json|```/g, '').trim();
  try {
    parsed = JSON.parse(clean);
  } catch {
    const m = clean.match(/\{[\s\S]*\}/);
    if (m) { try { parsed = JSON.parse(m[0]); } catch {} }
  }
}

// 6. Determine category — use fallback if anything failed or invalid
let category;
let confidence;
let reasoning;
let usedFallback = false;
let logStatus;

if (parsed && typeof parsed.category === 'string' && VALID_CATEGORIES.includes(parsed.category)) {
  category = parsed.category;
  confidence = typeof parsed.confidence === 'number' ? Math.max(0, Math.min(1, parsed.confidence)) : null;
  reasoning = String(parsed.reasoning || '').slice(0, 1000);
  logStatus = 'success';
} else {
  category = 'business';
  confidence = 0.3;
  reasoning = 'Classification fallback — low-confidence default';
  usedFallback = true;
  logStatus = claudeOk ? 'parse_fallback' : 'fallback';
}

// 7. Look up rpm_benchmarks
let benchmark = await lookupBenchmark(category);

// Safety net: if lookup fails for any reason, fall back to business
if (!benchmark) {
  category = 'business';
  usedFallback = true;
  logStatus = 'benchmark_fallback';
  reasoning = reasoning + ' | benchmark row missing, falling back to business';
  benchmark = await lookupBenchmark('business');
}

// Hard guard: if even the business row is missing, bail with server-side fallback values.
if (!benchmark) {
  benchmark = { rpm_low: 8, rpm_mid: 15, rpm_high: 25, display_name: 'Business' };
  logStatus = 'benchmark_hard_fallback';
}

const rpmLow = Number(benchmark.rpm_low);
const rpmMid = Number(benchmark.rpm_mid);
const rpmHigh = Number(benchmark.rpm_high);
const revenueScore = computeRevenueScore(rpmMid);

// 8. PATCH project
const nowIso = new Date().toISOString();
try {
  await patchProject({
    niche_rpm_category: category,
    estimated_rpm_low: rpmLow,
    estimated_rpm_mid: rpmMid,
    estimated_rpm_high: rpmHigh,
    revenue_potential_score: revenueScore,
    rpm_classified_at: nowIso
  });
} catch (e) {
  await logProduction('patch_project_failed', 'error', Date.now() - runStart, 0, retryCount);
  throw e;
}

// 9. Log production_logs row
// Cost estimate: Opus classify ~ $0.01 per run on success; $0 on full fallback.
const costUsd = claudeOk ? 0.01 : 0;
await logProduction('claude_opus_classify', logStatus, claudeDuration, costUsd, retryCount);

// 10. Respond with structured payload
return [{
  json: {
    success: true,
    project_id: projectId,
    category,
    rpm_low: rpmLow,
    rpm_mid: rpmMid,
    rpm_high: rpmHigh,
    revenue_potential_score: revenueScore,
    classification_confidence: confidence,
    reasoning,
    classified_by_fallback: usedFallback,
    claude_ok: claudeOk,
    claude_error: claudeOk ? null : claudeError,
    retry_count: retryCount,
    rpm_classified_at: nowIso,
    via_webhook: viaWebhook
  }
}];
